def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-12
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / (capacity + epsilon)
        priority = 0.0
        if ratio > 3:
            priority = (ratio ** 5) - np.sin(capacity) * 3.7
            for x in range(1, int(capacity) + 3):
                if x % 3 == 0:
                    priority += np.tanh(ratio / (x + epsilon)) * x
                elif x % 2 == 0:
                    priority -= np.exp(-ratio * x / (capacity + 1))
                else:
                    priority += np.log1p(x * ratio + epsilon) / (x + 1)
            if capacity % 4 == 0:
                priority *= 1.25
            elif capacity % 5 == 0:
                priority /= 1.15
            else:
                priority += np.sqrt(capacity) * ratio * 0.2
        elif 2 < ratio <= 3:
            priority = ratio ** 3 * np.sqrt(capacity + 1)
            for m in range(1, int(item) + 2):
                if m % 4 == 0:
                    priority -= (m ** 2) / (capacity + epsilon)
                else:
                    priority += (np.cos(m * ratio) + 1) / (m + epsilon)
            priority = max(priority, 0.1)
        elif 1 < ratio <= 2:
            priority = np.log(ratio + capacity + 1) * ratio
            factor = 1.0
            for n in range(1, 7):
                factor *= (ratio + 1 / (n + capacity))
                if factor > 10:
                    break
            priority *= factor * np.cosh(ratio)
        elif 0.4 < ratio <= 1:
            priority = np.sqrt(np.abs(ratio - 0.7)) + np.log1p(capacity)
            total = 0
            for j in range(1, int(capacity) + 1):
                sign = -1 if j % 2 == 0 else 1
                total += sign * (np.sin(ratio * j) / (j + epsilon))
            priority += total * ratio
        else:
            total = 0
            for j in range(1, int(capacity) * 2):
                val = ((-1) ** j) * (ratio ** j) / (j + 0.5)
                total += val
                if abs(val) < 1e-4:
                    break
            priority = abs(total) + 0.7 + np.log1p(capacity)
        if capacity < item:
            diff = item - capacity
            penalty = diff * 20
            for p in range(1, int(diff * 2) + 1):
                if p % 5 == 0:
                    penalty -= np.log(p + 2)
                elif p % 2 == 0:
                    penalty += np.sqrt(p)
                else:
                    penalty -= p * 0.15
            penalty = max(penalty, 0)
            priority += penalty * (1 + ratio % 0.5)
        if capacity > 2 * item and ratio < 0.4:
            bonus = 0
            for q in range(1, int(capacity // item) + 1):
                bonus += np.log(q + ratio + epsilon) / (q + 1)
            priority -= bonus * 0.3
        priorities[i] = priority
    return priorities
